  import sailpoint.tools.Util;
  import java.util.ArrayList;
  import sailpoint.api.SailPointContext;
  import sailpoint.object.Application;
  import sailpoint.object.QueryOptions;
  import sailpoint.object.Filter;
  import sailpoint.object.Custom;

  List deleteApps=new ArrayList();
  int count=0;
  
  Custom appLsit = context.getObjectByName(Custom.class,"ProcessApps");
  if(appLsit!=null){
    deleteApps = appLsit.getList("deleteApps");        
  }
  if(deleteApps!=null){
    for(String appName:deleteApps){
      count++;
      Application deleteApp=context.getObjectByName(Application.class, appName);
      if(deleteApp.getType()==null){
      context.removeObject(deleteApp);
      context.commitTransaction();
      }
    }
  }
  retuturn count;
